import pytest
from hydro.stage_cost_function import ProxyStageCostFunction
from hydro.bellman import BellmanValuesProxy
from hydro.trajectories import OptimalTrajectories
from tqdm import tqdm
import numpy as np

dir_study = "test_data/two_nodes"
area1="area1"
pbar = tqdm(total=0, disable=True)
proxy = ProxyStageCostFunction(dir_study=dir_study,
              name_area=area1,
              MC_years=10,
              alpha=2,
              pbar=pbar)

bellman_values = BellmanValuesProxy(proxy=proxy,
                                    PENALTY_FACTOR=0.4,
                                    pbar=pbar)


